511	  async seal(request: SealRequest): Promise<SealResult> {
512	    const state = await this.ensureReady(request.codexName);
513	    const clonePath = this.bareClonePath(state.name);
514	    const maxRetries = request.maxRetries ?? this.maxMergeRetries;
515	
516	    const defaultBranch = await resolveDefaultBranch(clonePath);
517	    const targetBranch = request.targetBranch ?? defaultBranch;
518	
519	    let strategy: 'fast-forward' | 'rebase' = 'fast-forward';
520	    let retries = 0;
521	
522	    // Fetch before sealing for freshness
523	    await this.performFetch(state.name);
524	
525	    // Advance the local sealed binding to the remote position if the remote
526	    // has moved ahead (e.g. commits pushed outside the Scriptorium).
527	    // This ensures seal compares against the latest remote ref, not a
528	    // potentially stale local one — preventing push failures.
529	    await this.advanceToRemote(state.name, targetBranch);
530	
531	    // Attempt ff-only merge, with rebase retry loop
532	    while (retries <= maxRetries) {
533	      try {
534	        // Try fast-forward merge: update the target branch ref to point at the source
535	        // In a bare repo, we use `git merge --ff-only` with the branch checked out,
536	        // but bare repos don't have a checkout. Instead, we verify ancestry and
537	        // update the ref directly.
538	        const targetRef = await resolveRef(clonePath, targetBranch);
539	        const sourceRef = await resolveRef(clonePath, request.sourceBranch);
540	
541	        // Check if source is already at target (nothing to seal)
542	        if (targetRef === sourceRef) {
543	          // Push before abandoning draft — if push fails the draft survives for inspection
544	          try {
545	            await git(['push', 'origin', targetBranch], clonePath);
546	          } catch (pushErr) {
547	            throw new Error(
548	              `Push failed after successful seal: ${pushErr instanceof Error ? pushErr.message : pushErr}`,
549	            );
550	          }
551	
552	          // Clean up draft unless keepDraft
553	          if (!request.keepDraft) {
554	            await this.abandonDraft({
555	              codexName: request.codexName,
556	              branch: request.sourceBranch,
557	              force: true,
558	            });
559	          }
560	          return { success: true, strategy, retries, sealedCommit: targetRef, inscriptionsSealed: 0 };
561	        }
562	
563	        // Check if target is an ancestor of source (ff is possible)
564	        const { stdout: mergeBase } = await git(
565	          ['merge-base', targetBranch, request.sourceBranch],
566	          clonePath,
567	        );
568	
569	        if (mergeBase === targetRef) {
